    'idx-news1-desc': { en: 'Netmarble\'s sci-fi MMORPG RF ONLINE NEXT launched globally on March 20, 2025, supporting cross-play across PC and mobile, built with Unreal Engine 5.', id: 'MMORPG sci-fi Netmarble RF ONLINE NEXT diluncurkan secara global pada 20 Maret 2025, mendukung cross-play di PC dan mobile, dibangun dengan Unreal Engine 5.' },
