    'bg-tips-title': { en: 'Essential Beginner Tips', id: 'Tips Penting Pemula' },
    'bg-tip1-title': { en: 'Resource Management', id: 'Manajemen Sumber Daya' },
    'bg-tip1-desc': { en: 'Gold and enhancement materials are precious early on — don\'t waste them on low-level gear. Focus resources on purple-quality or higher equipment from main quests, or prioritize enhancing Bio Suit core skills.', id: 'Emas dan material peningkatan sangat berharga di awal — jangan sia-siakan pada perlengkapan level rendah. Fokuskan sumber daya pada peralatan kualitas ungu atau lebih tinggi dari quest utama, atau prioritaskan peningkatan skill inti Bio Suit.' },
    'bg-tip2-title': { en: 'Common Mistakes', id: 'Kesalahan Umum' },
    'bg-tip2-desc': { en: 'Don\'t only train one Bio Suit! Although switching retains growth, each Bio Suit\'s skill levels need separate improvement. We recommend maining 2 Bio Suits with 1 backup.', id: 'Jangan hanya melatih satu Bio Suit! Meskipun peralihan mempertahankan pertumbuhan, level skill setiap Bio Suit perlu ditingkatkan secara terpisah. Kami merekomendasikan 2 Bio Suit utama dengan 1 cadangan.' },
    'bg-tip3-title': { en: 'Farming Advice', id: 'Saran Farming' },
    'bg-tip3-desc': { en: 'Don\'t rush into farming as a beginner — first reach mid-level and familiarize yourself with the economy. Participating in Mine Wars and daily dungeons provides stable resource income. See the Farming Guide for details.', id: 'Jangan terburu-buru farming sebagai pemula — pertama capai level menengah dan kenali ekonomi. Berpartisipasi dalam Perang Tambang dan dungeon harian memberikan pendapatan sumber daya yang stabil. Lihat Panduan Farming untuk detailnya.' },
    'bg-tl1': { en: 'Always claim daily login rewards — cumulative login rewards are very generous', id: 'Selalu klaim hadiah login harian — hadiah login kumulatif sangat melimpah' },
    'bg-tl2': { en: 'Prioritize daily and weekly quests — they are the main source of XP', id: 'Prioritaskan quest harian dan mingguan — mereka adalah sumber utama XP' },
    'bg-tl3': { en: 'Practice aerial combat immediately after unlocking the flight system — it\'s a key PVP advantage', id: 'Latih pertempuran udara segera setelah membuka sistem penerbangan — ini adalah keunggulan PVP kunci' },
    'bg-tl4': { en: 'The Exchange shop has great value transitional gear — don\'t rely solely on drops', id: 'Toko Bursa memiliki perlengkapan transisi bernilai tinggi — jangan hanya mengandalkan drop' },
    'bg-tl5': { en: 'Use auto-battle for daily dungeons, but always play manually for PVP and Mine Wars', id: 'Gunakan auto-battle untuk dungeon harian, tetapi selalu mainkan secara manual untuk PVP dan Perang Tambang' },
    'bg-tl6': { en: 'Follow the official event calendar — limited events often provide rare rewards and double XP', id: 'Ikuti kalender event resmi — event terbatas sering memberikan hadiah langka dan XP ganda' },
    'bg-tl7': { en: 'Join Discord or community groups for first-hand guides and team-forming information', id: 'Bergabung dengan Discord atau grup komunitas untuk panduan langsung dan informasi pembentukan tim' },

    // ===== EQUIPMENT PAGE =====
    'eq-page-title': { en: 'Equipment & Enhancement', id: 'Peralatan & Peningkatan' },
    'eq-page-sub': { en: 'Forge the strongest arsenal and fully enhance your combat power', id: 'Tempa arsenal terkuat dan tingkatkan kekuatan tempur Anda sepenuhnya' },
