    'eq-grade-title': { en: 'Equipment Grade System', id: 'Sistem Grade Peralatan' },
    'eq-grade-sub': { en: 'Equipment grade determines base stat caps and enhancement potential', id: 'Grade peralatan menentukan batas stat dasar dan potensi peningkatan' },
