    'eq-enhance-title': { en: 'Enhancement System Detailed', id: 'Sistem Peningkatan Detail' },
    'eq-enhance-rule': { en: 'Equipment Enhancement Rules', id: 'Aturan Peningkatan Peralatan' },
    'eq-enhance-desc': { en: 'Equipment enhancement is the core path to boosting combat power. Use enhancement stones and gold to enhance equipment, with each level increasing base stats. Higher enhance levels have lower success rates, but the game has a pity system — failure won\'t degrade or break equipment.', id: 'Peningkatan peralatan adalah jalur inti untuk meningkatkan kekuatan tempur. Gunakan batu peningkatan dan emas untuk meningkatkan peralatan, dengan setiap level meningkatkan stat dasar. Level enhance yang lebih tinggi memiliki tingkat keberhasilan lebih rendah, tetapi game memiliki sistem pity — kegagalan tidak akan menurunkan atau merusak peralatan.' },
    'eq-enhance-li1': { en: '+1~+5: 100% success rate, enhance without worry', id: '+1~+5: Tingkat keberhasilan 100%, tingkatkan tanpa khawatir' },
    'eq-enhance-li2': { en: '+6~+10: Success rate gradually decreases, use protection charms', id: '+6~+10: Tingkat keberhasilan menurun bertahap, gunakan charm perlindungan' },
    'eq-enhance-li3': { en: '+11~+15: High-risk phase, must use advanced protection charms', id: '+11~+15: Fase risiko tinggi, harus gunakan charm perlindungan lanjutan' },
    'eq-enhance-li4': { en: '+16~+20: Ultimate enhancement, requires legendary materials and massive resources', id: '+16~+20: Peningkatan ultimate, membutuhkan material legendaris dan sumber daya besar' },

